## Secure Implementation

### **Option 1: Comprehensive Secure Solution**

```javascript
const path = require('path');
const fs = require('fs').promises;
const crypto = require('crypto');

// Whitelist of allowed file extensions
const ALLOWED_EXTENSIONS = ['.pdf', '.jpg', '.jpeg', '.png', '.txt'];
const UPLOAD_DIR = path.resolve(__dirname, 'uploads');
const MAX_FILENAME_LENGTH = 255;

// Rate limiting middleware (use express-rate-limit in production)
const rateLimit = require('express-rate-limit');
const fileLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests, please try again later.'
});

// Authentication middleware (implement based on your auth system)
const requireAuth = (req, res, next) => {
  if (!req.session || !req.session.userId) {
    return res.status(401).json({ error: 'Authentication required' });
  }
  next();
};

app.get('/api/file', requireAuth, fileLimiter, async (req, res) => {
  try {
    const filename = req.query.name;

    // 1. Input validation
    if (!filename || typeof filename !== 'string') {
      return res.status(400).json({ error: 'Invalid filename' });
    }

    // 2. Length check
    if (filename.length > MAX_FILENAME_LENGTH) {
      return res.status(400).json({ error: 'Filename too long' });
    }

    // 3. Sanitize filename - remove any path components
    const sanitizedFilename = path.basename(filename);

    // 4. Check for path traversal attempts
    if (sanitizedFilename !== filename || filename.includes('..')) {
      console.warn(`Path traversal attempt detected: ${filename} from IP: ${req.ip}`);
      return res.status(400).json({ error: 'Invalid filename' });
    }

